// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

//  ------------------------------ | TESTIMONIAL 6 | ------------------------------  //

export default function Testimonial6() {
  const testimonials = [
    {
      name: "Joseph William",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    },
    {
      name: "John Doe",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    },
    {
      name: "Shirley Hoe",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    },
    {
      name: "Shirley Hoe",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    },
    {
      name: "Joseph William",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    },
    {
      name: "John Doe",
      role: "Manager at Apple",
      image:
        "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=256&h=256&auto=format&fit=crop",
      content:
        "At half-past eight the door opened, the policeman appeared and requesting them to follow him."
    }
  ];
  return (
    <section className="py-16 sm:py-24">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-12 gap-x-8 gap-y-4">
          <div className="col-span-12">
            <h2 className="mb-12">Testimonials</h2>
          </div>
          {testimonials.map((testimonial, index) => (
            <div
              key={index}
              className="col-span-12 md:col-span-6 lg:col-span-4"
            >
              <div className="flex flex-col gap-4">
                <div className="flex items-center gap-4">
                  <Avatar className="h-15 w-15">
                    <AvatarImage
                      src={testimonial.image}
                      alt={testimonial.name}
                    />
                    <AvatarFallback>
                      {testimonial.name.charAt(0)}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex flex-col gap-4">
                    <h5>{testimonial.name}</h5>
                    <p className="text-muted-foreground text-sm">
                      {testimonial.role}
                    </p>
                  </div>
                </div>
                <p className="text-muted-foreground">{testimonial.content}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
